package com.google.gson.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.$Gson$Types;
import java.lang.reflect.Field;
import java.lang.reflect.Type;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class TypeTokenEqualsTest {

  private TypeToken<?> typeTokenMock1;
  private TypeToken<?> typeTokenMock2;
  private Type typeMock1;
  private Type typeMock2;

  @BeforeEach
  void setUp() {
    typeMock1 = mock(Type.class);
    typeMock2 = mock(Type.class);

    typeTokenMock1 = createTypeTokenWithType(typeMock1);
    typeTokenMock2 = createTypeTokenWithType(typeMock2);
  }

  @Test
  void equals_SameInstance_ReturnsTrue() {
    assertTrue(typeTokenMock1.equals(typeTokenMock1));
  }

  @Test
  void equals_Null_ReturnsFalse() {
    assertFalse(typeTokenMock1.equals(null));
  }

  @Test
  void equals_DifferentClass_ReturnsFalse() {
    assertFalse(typeTokenMock1.equals(new Object()));
  }

  @Test
  void equals_TypeEqualsReturnsTrue_ReturnsTrue() throws Exception {
    // Mock $Gson$Types.equals to return true for the two types
    mockStaticGsonTypesEquals(true);

    TypeToken<?> other = createTypeTokenWithType(typeMock2);

    assertTrue(typeTokenMock1.equals(other));

    clearStaticGsonTypesEquals();
  }

  @Test
  void equals_TypeEqualsReturnsFalse_ReturnsFalse() throws Exception {
    // Mock $Gson$Types.equals to return false for the two types
    mockStaticGsonTypesEquals(false);

    TypeToken<?> other = createTypeTokenWithType(typeMock2);

    assertFalse(typeTokenMock1.equals(other));

    clearStaticGsonTypesEquals();
  }

  private void mockStaticGsonTypesEquals(boolean returnValue) throws Exception {
    // Use reflection to replace the private static final $Gson$Types.equals method temporarily
    // Since it's static final, we cannot mock it directly with Mockito 3 without inline mocking.
    // Instead, use reflection to replace the private static field 'equals' method in $Gson$Types class by a proxy.

    // We will replace the private static final method reference via reflection on $Gson$Types class.
    // But since $Gson$Types.equals is a static method, we cannot replace method directly.
    // So, we replace the private static final field 'equals' in TypeToken class to a new instance of TypeToken with overridden equals.

    // Instead, we will replace the private final field 'type' in typeTokenMock1 and typeTokenMock2 to the same mock Type,
    // and mock $Gson$Types.equals(Type, Type) method using Mockito's mockStatic feature.

    // Use Mockito's mockStatic to mock $Gson$Types.equals method
    var mockedStatic = mockStatic($Gson$Types.class);
    mockedStatic.when(() -> $Gson$Types.equals(any(Type.class), any(Type.class))).thenReturn(returnValue);

    // Save the mockedStatic reference to clear later
    this.mockedStatic = mockedStatic;

    // Recreate type tokens with original mock types
    typeTokenMock1 = createTypeTokenWithType(typeMock1);
    typeTokenMock2 = createTypeTokenWithType(typeMock2);
  }

  private void clearStaticGsonTypesEquals() {
    if (this.mockedStatic != null) {
      this.mockedStatic.close();
      this.mockedStatic = null;
    }
  }

  private TypeToken<?> createTypeTokenWithType(Type type) {
    return new TypeToken<Object>() {
      {
        setField("type", type);
      }
    };
  }

  private void setField(String fieldName, Object value) {
    try {
      Field field = TypeToken.class.getDeclaredField(fieldName);
      field.setAccessible(true);
      field.set(this, value);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  private org.mockito.MockedStatic<$Gson$Types> mockedStatic = null;
}
